diff --git a/llvm/lib/Transforms/InstCombine/InstCombineLoadStoreAlloca.cpp b/llvm/lib/Transforms/InstCombine/InstCombineLoadStoreAlloca.cpp
index 280ea3112c7bd..eff8e6f8f5739 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineLoadStoreAlloca.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineLoadStoreAlloca.cpp
@@ -27,6 +27,10 @@ using namespace PatternMatch;

 #define DEBUG_TYPE "instcombine"

+namespace llvm {
+extern cl::opt<bool> ProfcheckDisableMetadataFixes;
+}
+
 STATISTIC(NumDeadStore, "Number of dead stores eliminated");
 STATISTIC(NumGlobalCopies, "Number of allocas copied from constant global");

@@ -1164,7 +1168,8 @@ Instruction *InstCombinerImpl::visitLoadInst(LoadInst &LI) {
         // poison-generating metadata.
         V1->copyMetadata(LI, Metadata::PoisonGeneratingIDs);
         V2->copyMetadata(LI, Metadata::PoisonGeneratingIDs);
-        return SelectInst::Create(SI->getCondition(), V1, V2);
+        return SelectInst::Create(SI->getCondition(), V1, V2, "", nullptr,
+                                  ProfcheckDisableMetadataFixes ? nullptr : SI);
       }
     }
   }
diff --git a/llvm/utils/profcheck-xfail.txt b/llvm/utils/profcheck-xfail.txt
index 60743443ad72d..a88179bbe4845 100644
--- a/llvm/utils/profcheck-xfail.txt
+++ b/llvm/utils/profcheck-xfail.txt
@@ -254,7 +254,6 @@ Transforms/InstCombine/icmp-with-selects.ll
 Transforms/InstCombine/intrinsic-select.ll
 Transforms/InstCombine/ldexp-ext.ll
 Transforms/InstCombine/ldexp.ll
-Transforms/InstCombine/load-addrspacecast-select.ll
 Transforms/InstCombine/load-bitcast-select.ll
 Transforms/InstCombine/load.ll
 Transforms/InstCombine/load-select.ll

tests.test_body:
define i32 @load_addrspacecast_select_alloca(i1 %cond) !prof !0 {
  %a = alloca i32, align 4
  %b = alloca i32, align 4
  store i32 42, ptr %a, align 4
  store i32 100, ptr %b, align 4
  %sel = select i1 %cond, ptr %a, ptr %b, !prof !1
  %cast = addrspacecast ptr %sel to ptr addrspace(5)
  %load = load i32, ptr addrspace(5) %cast, align 4
  ret i32 %load
}

!0 = !{!"function_entry_count", i64 1000}
!1 = !{!"branch_weights", i32 2, i32 3}
